445: // resyncChan returns a channel which will receive something when a resync is
446: // required, and a cleanup function.
447: func (r *Reflector) resyncChan() (<-chan time.Time, func() bool) {
448: 	if r.resyncPeriod == 0 {
449: 		// nothing will ever be sent down this channel
450: 		return nil, func() bool { return false }
451: 	}
452: 	// The cleanup function is required: imagine the scenario where watches
453: 	// always fail so we end up listing frequently. Then, if we don't
454: 	// manually stop the timer, we could end up with many timers active
455: 	// concurrently.
456: 	t := r.clock.NewTimer(r.resyncPeriod)
457: 	return t.C(), t.Stop
458: }
