855: func determineResyncPeriod(logger klog.Logger, desired, check time.Duration) time.Duration {
856: 	if desired == 0 {
857: 		return desired
858: 	}
859: 	if check == 0 {
860: 		logger.Info("Warning: the specified resyncPeriod is invalid because this shared informer doesn't support resyncing", "desired", desired)
861: 		return 0
862: 	}
863: 	if desired < check {
864: 		logger.Info("Warning: the specified resyncPeriod is being increased to the minimum resyncCheckPeriod", "desired", desired, "resyncCheckPeriod", check)
865: 		return check
866: 	}
