876: func (s *sharedIndexInformer) AddEventHandlerWithOptions(handler ResourceEventHandler, options HandlerOptions) (ResourceEventHandlerRegistration, error) {
877: 	s.startedLock.Lock()
878: 	defer s.startedLock.Unlock()
879: 
880: 	if s.stopped {
881: 		return nil, fmt.Errorf("handler %v was not added to shared informer because it has stopped already", handler)
882: 	}
883: 
884: 	logger := ptr.Deref(options.Logger, klog.Background())
885: 	resyncPeriod := ptr.Deref(options.ResyncPeriod, s.defaultEventHandlerResyncPeriod)
886: 	if resyncPeriod > 0 {
887: 		if resyncPeriod < minimumResyncPeriod {
888: 			logger.Info("Warning: resync period is too small. Changing it to the minimum allowed value", "resyncPeriod", resyncPeriod, "minimumResyncPeriod", minimumResyncPeriod)
889: 			resyncPeriod = minimumResyncPeriod
890: 		}
891: 
892: 		if resyncPeriod < s.resyncCheckPeriod {
893: 			if s.started {
894: 				logger.Info("Warning: resync period is smaller than resync check period and the informer has already started. Changing it to the resync check period", "resyncPeriod", resyncPeriod, "resyncCheckPeriod", s.resyncCheckPeriod)
895: 
896: 				resyncPeriod = s.resyncCheckPeriod
897: 			} else {
898: 				// if the event handler's resyncPeriod is smaller than the current resyncCheckPeriod, update
899: 				// resyncCheckPeriod to match resyncPeriod and adjust the resync periods of all the listeners
900: 				// accordingly
901: 				s.resyncCheckPeriod = resyncPeriod
902: 				s.processor.resyncCheckPeriodChanged(logger, resyncPeriod)
903: 			}
904: 		}
905: 	}
906: 
907: 	listener := newProcessListener(logger, handler, resyncPeriod, determineResyncPeriod(logger, resyncPeriod, s.resyncCheckPeriod), s.clock.Now(), initialBufferSize, s.HasSyncedChecker())
908: 
909: 	if !s.started {
910: 		return s.processor.addListener(listener), nil
911: 	}
912: 
913: 	// in order to safely join, we have to
914: 	// 1. stop sending add/update/delete notifications
915: 	// 2. do a list against the store
916: 	// 3. send synthetic "Add" events to the new handler
917: 	// 4. unblock
918: 	s.blockDeltas.Lock()
919: 	defer s.blockDeltas.Unlock()
920: 
921: 	handle := s.processor.addListener(listener)
922: 	for _, item := range s.indexer.List() {
923: 		// Note that we enqueue these notifications with the lock held
924: 		// and before returning the handle. That means there is never a
925: 		// chance for anyone to call the handle's HasSynced method in a
926: 		// state when it would falsely return true (i.e., when the
927: 		// shared informer is synced but it has not observed an Add
928: 		// with isInitialList being true, nor when the thread
929: 		// processing notifications somehow goes faster than this
930: 		// thread adding them and the counter is temporarily zero).
931: 		listener.add(addNotification{newObj: item, isInInitialList: true})
932: 	}
933: 
934: 	// Initial list is added, now we can allow the listener to detect that "upstream has synced".
935: 	s.processor.wg.Start(listener.watchSynced)
936: 
937: 	return handle, nil
938: }
