940: func (s *sharedIndexInformer) handleDeltas(logger klog.Logger, obj interface{}, isInInitialList bool) error {
941: 	s.blockDeltas.Lock()
942: 	defer s.blockDeltas.Unlock()
943: 
944: 	if deltas, ok := obj.(Deltas); ok {
945: 		return processDeltas(logger, s, s.indexer, deltas, isInInitialList, s.keyFunc)
946: 	}
947: 	return errors.New("object given as Process argument is not Deltas")
948: }
