965: func (s *sharedIndexInformer) OnUpdate(old, new interface{}) {
966: 	isSync := false
967: 
968: 	// If is a Sync event, isSync should be true
969: 	// If is a Replaced event, isSync is true if resource version is unchanged.
970: 	// If RV is unchanged: this is a Sync/Replaced event, so isSync is true
971: 
972: 	if accessor, err := meta.Accessor(new); err == nil {
973: 		if oldAccessor, err := meta.Accessor(old); err == nil {
974: 			// Events that didn't change resourceVersion are treated as resync events
975: 			// and only propagated to listeners that requested resync
976: 			isSync = accessor.GetResourceVersion() == oldAccessor.GetResourceVersion()
977: 		}
978: 	}
979: 
980: 	// Invocation of this function is locked under s.blockDeltas, so it is
981: 	// safe to distribute the notification
982: 	s.cacheMutationDetector.AddObject(new)
983: 	s.processor.distribute(updateNotification{oldObj: old, newObj: new}, isSync)
984: }
